// GET /api/iterations - 获取迭代列表（分页）
server.get('/api/iterations', async (request, reply) => {
  const { page = 1, limit = 20, status } = request.query as any;
  const result = await iterationService.list({
    page,
    limit,
    status
  });
  return result;
});

// GET /api/iterations/:id - 获取迭代详情
server.get('/api/iterations/:id', async (request, reply) => {
  const { id } = request.params as { id: string };
  const iteration = await iterationService.detail(parseInt(id));
  return iteration;
});

// POST /api/iterations/:id/rollback - 回滚到指定迭代
server.post('/api/iterations/:id/rollback', async (request, reply) => {
  const { id } = request.params as { id: string };
  const result = await iterationService.rollback(parseInt(id));
  return result;
});
